<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div class="padding-t_10">
            <div class="row">
                <div id="tabs" class="col-sm-12 col-md-12 col-lg-12 col-xl-12">
                    <div class="form-content">
                        <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 p-0" id="clientbill">
                            <div class="col-md-12 p-0">
                                <div class="theme-primary partition p-actions-expand tablehead">
                                    <span id="titleName" class="p-name text-white"> {{ QuotationData.QUOTATIONNUMBER
                                    }}</span>
                                    <span class="p-actions float-right">

                                        
                                        <a v-if="Code == '1'" :title="$t('BacktoList')" @click="BackToList" class="p-action-btn text-white float-right">
                                            <em class="fa fa-angle-double-left"></em><br><span>{{ $t('BacktoList')
                                            }}</span>
                                            
                                        </a>
                                        <a v-if="UserType == 'CL' && QuotationData.STATUS == 'ACT'" :title="$t('Edit')"
                                            class="p-action-btn text-white">
                                            <em class="fa fa-pencil"></em><br><span>{{ $t('Edit') }}</span>
                                        </a>
                                        <a v-if="UserType == 'CL' && QuotationData.QUOTATIONNUMBER != 'Draft Mode' && QuotationData.STATUS != 'QUOTE_REJ' && QuotationData.STATUS != 'QUOTE_APPR'"
                                            :title="$t('SendEmail')" class="p-action-btn text-white" href="javascript:;"
                                            id="aSend">
                                            <em class="fa fa-paper-plane"></em><br><span>{{ $t('SendEmail') }}</span>
                                        </a>
                                       
                                            <a href="javascript:;" @click="printInvoice" class="btn btn-success mr-2 mt-1"
                                            title=""><i class="fa fa-print pr-2"></i>{{ $t("Print") }}
                                        </a>

                                        <a href="javascript:;" @click="downloadInvoice" class="btn btn-info mr-2 mt-1"
                                            title=""><i class="fa fa-download pr-2"></i>{{ $t("DownloadInvoice") }}
                                        </a>

                                            <!-- <a v-if="QuotationData.STATUS == 'ACT'" :title="$t('Delete')"
                                            id="DeleteQuotation"  href="javascript:;" class="p-action-btn text-white">
                                            <em class="fa fa-trash-o"></em><br><span>{{ $t('Delete') }}</span>
                                        </a> -->

                                                   
                                     
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            <div class="col-md-12 p-0">
                <div style="height: 600px;">
                    <div v-html="TemplateContent" id="viewer"></div>
                </div>
            </div>
        </div>
    </section>
</template>
<script>
import DataService from '../../../services/DataService';
import { jsPDF } from "jspdf";
export default {

    data() {
        return {
            isLoading: false,
            QuotationId: null,
            Code: null,
            QuotationData: [],
            UserType: null,
            parameter: [],
            reportPath: '',
            TemplateContent: '',
            currency: ''
        }
    },
    created: async function () {
        var ths = this;
        ths.Token = ths.GetUserInfo.Token;
        ths.QuotationId = ths.$route.params.QuotationId;
        ths.Code = ths.$route.params.Code;
        ths.UserType = ths.GetUserInfo.UserType;
        await ths.FetchData();
        ths.ViewQuotation();
    },

    methods: {

        BackToList()
        { 
            this.$router.push({name :'QuotationList'});
        },
        async printInvoice() {
            const svgElement = document.getElementById("accountNoBarCode");
            const barcodePngData = "";
            if (svgElement != null) {
                const svgData = new XMLSerializer().serializeToString(svgElement);
            }
            const canvas = document.createElement("canvas");
            const ctx = canvas.getContext("2d");
            const img = new Image();
            canvas.width = img.width;
            canvas.height = img.height;
            ctx.drawImage(img, 0, 0);
            let base64Image = "";
            const match = this.TemplateContent.match(/<img[^>]*src=["']([^"']+)["'][^>]*>/i);
            if (match) {
                const logoSrc = match[1];
                if (logoSrc) {
                    base64Image = await this.ConvertLogoBase64(logoSrc);
                }
            }

            let updatedHtml = "";
            if (svgElement != null) {
                updatedHtml = this.TemplateContent
                    .replace(/<svg.*?<\/svg>/s, `<img src="${barcodePngData}" style="max-width: 100%;" />`)
                    .replace(/<img id="invoiceLogo".*?>/s, `<img src="${base64Image}" style="max-width: 150px;" />`);
            }
            else {
                updatedHtml = this.TemplateContent.replace(/<img id="invoiceLogo".*?>/s, `<img src="${base64Image}" style="max-width: 150px;" />`);
            }
            const iframe = document.createElement("iframe");
            iframe.style.position = "absolute";
            iframe.style.width = "0";
            iframe.style.height = "0";
            iframe.style.border = "none";

            document.body.appendChild(iframe);

            const iframeDoc = iframe.contentDocument || iframe.contentWindow.document;

            iframeDoc.open();
            iframeDoc.write(`
      <!DOCTYPE html>
      <html>
        <head>
          <title>Invoice</title>
          <style>
            body { font-family: Arial, sans-serif; margin: 20px; }
            table { width: 100%; border-collapse: collapse; margin-top: 20px; }
            th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
            img { display: block; margin-bottom: 10px; }
          </style>
        </head>
        <body>
          ${updatedHtml}
        </body>
      </html>
    `);
            iframeDoc.close();

            // const barcodeImg = iframeDoc.getElementById("barcodeImage");
            // console.log("barcodeImg",barcodeImg)
            //if (barcodeImg) {
            // barcodeImg.onload = () => {

            // iframe.contentWindow.focus();
            // iframe.contentWindow.print();
            //setTimeout(() => document.body.removeChild(iframe), 1000);
            //};
            //} 
            //else {
            // Fallback if barcode image is not found
            iframe.contentWindow.focus();
            iframe.contentWindow.print();
            setTimeout(() => document.body.removeChild(iframe), 500);
            //}
            //};
            //   img.src = svgUrl;
        },
        async ConvertLogoBase64(logoUrl) {
            try {
                let params = `imageUrl=${encodeURIComponent(logoUrl)}`;
                const response = await DataService.getConvertBase64(params);
                if (response.status === 200 && response.data && response.data.base64Image) {
                    const base64WithPrefix = response.data.base64Image;
                    return base64WithPrefix;
                } else {
                    throw new Error("Invalid Base64 response");
                }
            } catch (error) {
                return null;
            }
        },
        async downloadInvoice() {
            var vueObj = this;
            vueObj.isLoading = true;

            const doc = new jsPDF({
                unit: 'mm',
                format: 'a4',
            });

            const pageWidth = 185;
            const pageHeight = 297;
            const margin = 0;
            const contentWidth = pageWidth - 2 * margin;
            const contentHeight = pageHeight - 2 * margin;
            const element = document.createElement('div');
            element.innerHTML = this.TemplateContent;
            element.style.width = `${contentWidth}mm`;
            element.style.height = 'auto';
            element.style.boxSizing = 'border-box';
            element.style.padding = '10mm';
            element.style.alignContent = 'center';
            document.body.appendChild(element);
            const elementWidth = element.offsetWidth;
            const elementHeight = element.offsetHeight;
            const scaleX = contentWidth / elementWidth;
            const scaleY = contentHeight / elementHeight;
            const scaleFactor = Math.min(scaleX, scaleY);
            const images = element.querySelectorAll('img');
            document.body.removeChild(element);
            for (let i = 0; i < images.length; i++) {
                const img = images[i];
                const base64Image = await this.ConvertLogoBase64(img.src);
                base64Image ==null ? `` : base64Image;
                img.src = base64Image;
            }
            doc.html(element, {
                x: margin,
                y: margin,
                html2canvas: {
                    scale: scaleFactor,
                    logging: true,
                    useCORS: true,
                },
                callback: function (doc) {
                    vueObj.isLoading = false;
                    doc.save('invoice.pdf');
                },
            });
        },
        async FetchData() {
            var ths = this;
            var url = `quotationId=${ths.QuotationId}&code=${ths.Code}`;

            await DataService.DisplayQuotation(url).then((response) => {
                if (response.data.result.DATA.length > 0) {
                    ths.QuotationData = response.data.result.DATA[0];
                    ths.templateId = ths.QuotationData.TEMPLATEID;
                    ths.quotationId = ths.QuotationData.QUOTATIONID;
                    ths.ViewQuotation();
                }
            });
        },

        ViewQuotation() {
            var vm = this;
            vm.isLoading = true;

            var url = `template_id=${vm.templateId}&Quote_id=${vm.quotationId}`;

            DataService.GetTemplateById(url).then((response) => {
                if (response.data !== '') {
                    vm.TemplateContent = vm.ReplaceTemplateVariables(response.data.templateData, response.data.quote.result[0]);
                }
                vm.isLoading = false;
            });
        },
        ReplaceTemplateVariables(template, item) {
    if (!template || !item) return template;
    debugger;
    const u = item.USER_DETAIL?.[0] || {};
    const q = item.QUOTATION_DETAIL || [];
    this.currency = u.ISO_CODE;
    let totalAmount = 0;
    let subtotal = 0;
    let adjustment_type_name = 'Discounts';
    q.forEach((element) => {
        subtotal += element.TOTAL_LINE_PRICE;
        totalAmount += element.TOTAL_LINE_PRICE;
    });

    var taxItem = {}; 
    var discountItem = {}; 

    if (item.BILL_ADJUSTMENTS) {
        item.BILL_ADJUSTMENTS.forEach((element) => {
            if (element.adjustment_type == 'Tax') {
                adjustment_type_name = element.adjustment_type;
                totalAmount += element.adjustment_amount;
                taxItem = element; 
            } else {
                totalAmount -= element.adjustment_amount; 
                discountItem = element; 
            }
        });
    }

    const taxItemsArray = taxItem ? [taxItem] : [];
    const discountItemsArray = discountItem ? [discountItem] : [];

    const replacements = {
        '@BillAddress@': u.COMPANY_LOCATION || '--',
        '@BillCity@': u.COMPANY_CITY || '--',
        '@BillState@': u.COMPANY_STATE || '--',
        '@BillCountry@': u.COMPANY_COUNTRY || '--',
        '@BillZip@': u.COMPANY_PINCODE || '--',
        '@ClientBillAddress@': u.USER_ADDRESS_1 || '--',
        '@ClientBillCity@': u.USER_CITY || '--',
        '@ClientBillState@': u.USER_STATE || '--',
        '@ClientBillCountry@': u.COUNTRY_NAME || '--',
        '@ClientBillZip@': u.ZIP_CODE || '--',
        '@BillPhone@': u.COMPANY_PHONE || '--',
        '@ClientBillPhone@': item.clientPhone || '--',
        '@Email@': u.COMPANY_EMAIL || '',
        '@ClientProjectName@': u.PROJECT_NAME || '',
        '@CompanyName@': u.COMPANY_NAME || '',
        '@ClientNameOnBill@': [u.FIRST_NAME, u.LAST_NAME].filter(Boolean).join(' ') || '',
        '@Logo@': `<img src="${u.company_logo || ''}" alt="Company Logo" height="50">`,
        '@BillNumber@': q[0].QUOTATION_NUMBER || '',
        '@BillIssueDate@': q[0].START_DATE ? this.$d(new Date(q[0].START_DATE)) : '',
        '@BillDueDate@': q[0].END_DATE ? this.$d(new Date(q[0].END_DATE)) : '',
        '@BillDateComments@': '--',
        '@SubTotal@': this.$n(subtotal, "currency", this.$getLocaleByCurrency(u.ISO_CODE)),
        '@BillAdjustments@': '',
        '@BillTotalNoAdv@': this.$n(totalAmount, "currency", this.$getLocaleByCurrency(u.ISO_CODE)),
        '@BillAdvanceAmount@': this.$n(0, "currency", this.$getLocaleByCurrency(u.ISO_CODE)),
        '@BillNetTotal@': this.$n(totalAmount, "currency", this.$getLocaleByCurrency(u.ISO_CODE)),
        '@Currency@': '',
        '@BillDescription@': q[0].DESCRIPTION || '--',
        '@Items@': this.GenerateItemsTable(q || []),
        '@ItemsValue@': this.GenerateItemsValueTableGST(taxItemsArray),
        '@ItemsDiscountValue@': this.GenerateItemsValueTableDiscount(discountItemsArray),
        '@GSTItem@':this.GenerateItemsTableGST(taxItemsArray),
        '@ItemsDiscountItem@' : this.GenerateItemsTableDiscount(discountItemsArray)
    };

    for (const [key, value] of Object.entries(replacements)) {
        const regex = new RegExp(key, 'g');
        template = template.replace(regex, value);
    }

    return template;
},
        GenerateItemsTable(items) {
            if (!items.length) return '<p>No items found.</p>';
            let html = `
                <table width="100%" border="1" cellspacing="0" cellpadding="5" style="border-collapse: collapse; font-size: 0.9em;">
                    <thead>
                        <tr style="background-color:#f2f2f2;">
                            <th align="left">#</th>
                            <th align="left">Product Name</th>
                            <th align="left">Rate X Qty</th>
                            <th align="left">Amount (${this.currency})</th>
                        </tr>
                    </thead>
                    <tbody>`;

            items.forEach((item, index) => {
                html += `
                    <tr>
                        <td>${index + 1}</td>
                        <td>${item.ITEM || ''}</td>
                        <td align="left">${ this.$n(item.BILLING,"currency", this.$getLocaleByCurrency(this.currency)) + ' * ' + item.QUANTITY|| 0}</td>
                        <td align="left">${this.$n(item.BILLED_AMT,"currency", this.$getLocaleByCurrency(this.currency)) || 0}</td>
                    </tr>
                `;
            });

            html += '</tbody></table></br>';
            return html;
        },
        GenerateItemsTableGST(items) {
    if (!items.length) return '--';

    let html = `<table width="100%"  cellspacing="0" cellpadding="1" style="border-collapse: collapse; font-size: 0.9em;">
                    <tbody>`;
    items.forEach((item, index) => {
        html += `
            <tr style="padding-top: 15px;">
                <td>${  item.adjustment_name +'('+ item.adjustment_percentage +'%)' || ''}</td>
            </tr>
        `;
    });

    html += '</tbody></table>';
    return html;
},
       GenerateItemsTableDiscount(items) {
    if (!items.length) return '<p>--</p>'; 

    let html = `<table width="100%"  cellspacing="0" cellpadding="1" style="border-collapse: collapse; font-size: 0.9em;">
                    <thead>
                    </thead>
                    <tbody>`;
    items.forEach((item, index) => {
        html += `
            <tr>

               <td>${ item.adjustment_name +'(' + item.adjustment_percentage +'%)' || ''}</td>
            </tr>
        `;
    });

    html += '</tbody></table>';
    return html;
},
        GenerateItemsValueTableGST(items) {
    if (!items.length) return '--';

    let html = `<table width="100%"  cellspacing="0" cellpadding="1" style="border-collapse: collapse; font-size: 0.9em;">
                    <tbody>`;
    items.forEach((item, index) => {
        html += `
            <tr style="padding-top: 15px;">
                <td>${this.$n(item.adjustment_amount, "currency", this.$getLocaleByCurrency(this.currency)) || ''}</td>
            </tr>
        `;
    });

    html += '</tbody></table>';
    return html;
},
       GenerateItemsValueTableDiscount(items) {
    if (!items.length) return '<p>--</p>'; 

    let html = `<table width="100%"  cellspacing="0" cellpadding="1" style="border-collapse: collapse; font-size: 0.9em;">
                    <thead>
                    </thead>
                    <tbody>`;
    items.forEach((item, index) => {
        html += `
            <tr>

                <td>${this.$n(item.adjustment_amount, "currency", this.$getLocaleByCurrency(this.currency)) || ''}</td>
            </tr>
        `;
    });

    html += '</tbody></table>';
    return html;
}

    }
}
</script>